public interface INoteService
{
    Task<List<Note>> GetNotesAsync(int estimateId);
    Task<Note> GetNoteAsync(int noteId);
    Task AddNoteAsync(Note note);
    Task UpdateNoteAsync(Note note);
    Task DeleteNoteAsync(int noteId);
}

public class NoteService : INoteService
{
    private readonly ApplicationDbContext _context;

    public NoteService(ApplicationDbContext context)
    {
        _context = context;
    }

    public async Task<List<Note>> GetNotesAsync(int estimateId)
    {
        return await _context.Notes.Where(n => n.EstimateId == estimateId).ToListAsync();
    }

    public async Task<Note> GetNoteAsync(int noteId)
    {
        return await _context.Notes.FindAsync(noteId);
    }

    public async Task AddNoteAsync(Note note)
    {
        _context.Notes.Add(note);
        await _context.SaveChangesAsync();
    }

    public async Task UpdateNoteAsync(Note note)
    {
        _context.Entry(note).State = EntityState.Modified;
        await _context.SaveChangesAsync();
    }

    public async Task DeleteNoteAsync(int noteId)
    {
        var note = await _context.Notes.FindAsync(noteId);
        if (note != null)
        {
            _context.Notes.Remove(note);
            await _context.SaveChangesAsync();
        }
    }
}
```

